params.script:
// n_choice — N択分類 + コンテキスト保存（決定論・正本 v4）
// 用途: DTMF（プッシュ番号）または音声キーワードで N 択メニューを判定する汎用エンジン。
//       OpenAI を使わず、正規化 → DTMF_MAP → token/keyword 正規表現で決定論的に分類する。
// 出力: 選択肢ラベル / NO_RESULT
// ランタイム: Brekeke @General$Script（Nashorn / ES5 only）
// 由来: 髙橋 VFB-Script reference/scripts/n_choice.js (v4) を VFB の DoD に載せた正本。
// @part-id: n_choice
// @engine-version: v4
//
// 【テンプレート（設定行 — 施設・設問ごとに充填。hash 認定では除外対象）】
//   入力_発信元確認          直前の入力（STT/DTMF）モジュール名（wiring）
//   callerType          保存先 context 名（例: callerType）（wiring）
//   TEXT  context の displayType（例: TEXT）（wiring）
//   {"1":"患者本人・家族","2":"連携医療機関","3":"行政"}              {"1":"ラベルA","2":"ラベルB",...} 数字→ラベル（spec）
//   []             [{regex:"...",result:"ラベル"},...] 完全一致トークン（spec）
//   [][{digit:"1",regex:"...",result:"ラベル"},...] 先頭数字＋語（spec）
//   []     [{regex:"...",result:"ラベル"},...] 複合語（先に評価）（spec）
//   [{"regex":"本人|家族|患者|母|父|親|息子|娘","result":"患者本人・家族"},{"regex":"クリニック|診療所|病院|医療機関|医院|連携先","result":"連携医療機関"},{"regex":"市役所|役所|役場|保健所|行政|地域包括|包括支援|福祉課","result":"行政"}]      [{regex:"...",result:"ラベル"},...] 単独キーワード（spec）
//
// 【判定順】空 → 正規化 → DTMF（単一数字）→ TOKEN → 先頭数字+語 → 複合 → 単独keyword
//          → filler のみ → no_match（いずれも NO_RESULT に倒す）

var logger = $runner.getLogger();
var INPUT_MODULE = "入力_発信元確認";
var CONTEXT_NAME = "callerType";
var CONTEXT_DISPLAY_TYPE = "TEXT";

// === コンテキスト保存関数群（VFB 共通流儀: save2db + setObject + checkpoint）===
function _saveCheckpoint(value) {
    try { if (!$ivr.connected()) return; $ivr.exec("save2db", "save", JSON.stringify({ contextField: { contextName: "checkpoint", displayType: "TEXT", value: value } })); } catch (e) { logger.error("[saveContext2DB] Checkpoint: " + e); }
}
function _setObj(k, v) { try { $ivr.setObject(k, v); } catch (e) { logger.error("[saveContext2DB] setObj: " + e); } }
function saveContext(val, name, type) {
    var rid = $ivr.getRID(); var mod = $runner.getCurrentModuleName();
    _saveCheckpoint(mod + "_IN"); _setObj("checkpoint." + rid, mod + "_IN");
    if (name && val) { var req = JSON.stringify({ contextField: { contextName: name, displayType: type || "TEXT", value: val } }); logger.info("[saveContext2DB] " + req); try { $ivr.exec("save2db", "save", req); $runner.setObject(name, val); } catch (e) { logger.error("[saveContext2DB] " + e); } }
    _saveCheckpoint(mod + "_OUT"); _setObj("checkpoint." + rid, mod + "_OUT"); _setObj("saveContext." + rid, true);
}
// === END ===

var input = $runner.getResult(INPUT_MODULE);
logger.info("[n_choice] raw input: " + input);

var result = null;
var source = "";

if (input === null || input === undefined || input === "") {
    result = "NO_RESULT"; source = "empty";
} else {
    var s = String(input);
    s = s.replace(/[０-９]/g, function(c) { return String.fromCharCode(c.charCodeAt(0) - 0xFEE0); });
    s = s.replace(/[、。,.:;!?！？「」『』（）()\s\r\n\t]/g, "");
    s = s.replace(/^(えーと|えーっと|えー|あのー|あの|うーんと|うーん|まー|まあ|そうですね|えっと|そのー|あー|んー|んーと|ねえ|ちょっと)+/g, "");
    s = s.replace(/(えーと|えーっと|えー|あのー|あの|うーんと|うーん|まー|まあ|そうですね|えっと|そのー|あー|んー|んーと|ねえ|ちょっと)+$/g, "");
    // 方言/敬語/タメ口 接尾辞除去 (DIALECT/POLITE/CASUAL)
    s = s.replace(/(だべさ|だべ|っしょ|べし|だす|んだ|じゃん|だよね|じゃね|やん|やねん|やで|やんか|やわ|ねん|やろ|じゃけん|じゃけ|けん|ばい|たい|さー|さあ)$/g, "");
    s = s.replace(/(でございます|ございます|いただけますか|いただきたい|させていただきたい|でしょうか|いたします|ですよね|ですわ|だわ)$/g, "");
    s = s.replace(/(だよ|だね|だぜ|だろ|じゃね|じゃん|っす|すか|かよ|だっけ|っけ|だわ|やん|やろ|やで|けど|けんど|だに|ずら|だら)$/g, "");
    s = s.replace(/(です|でお願いします|お願いします|なんですけど|にお願い|ですけど|なんですが|をお願い)$/g, "");
    // AmiVoice カテゴリ重複正規化: "再診再診" → "再診"
    if (s.length >= 4) {
        for (var dl = Math.floor(s.length / 2); dl >= 2; dl--) {
            var chunk = s.substring(0, dl);
            var rep = new RegExp("^(" + chunk.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")+$");
            if (rep.test(s)) { s = chunk; break; }
        }
    }
    var trimmed = s.replace(/^([0-9])(です|だ|でお願いします|でお願い|ね|よ|かな)+$/, "$1");
    if (trimmed !== s) { logger.info("[n_choice] trimmed: " + s + " => " + trimmed); s = trimmed; }
    logger.info("[n_choice] normalized: " + s);
    if (s === "") { result = "NO_RESULT"; source = "empty_after_normalize"; }

    // @spec-begin
    var DTMF_MAP = {"1":"患者本人・家族","2":"連携医療機関","3":"行政"};
    // @spec-end
    if (result === null && /^[0-9]$/.test(s)) {
        if (DTMF_MAP[s] !== undefined) { result = DTMF_MAP[s]; source = "dtmf"; }
        else { result = "NO_RESULT"; source = "dtmf_invalid"; }
    }

    // @spec-begin
    var TOKEN_MAP = [];
    // @spec-end
    if (result === null) {
        for (var ti = 0; ti < TOKEN_MAP.length; ti++) {
            if (new RegExp("^(" + TOKEN_MAP[ti].regex + ")$").test(s)) { result = TOKEN_MAP[ti].result; source = "token"; break; }
        }
    }

    // @spec-begin
    var DIGIT_KEYWORD_PATTERNS = [];
    // @spec-end
    if (result === null) {
        var hdm = s.match(/^([0-9])/);
        if (hdm !== null) {
            for (var dk = 0; dk < DIGIT_KEYWORD_PATTERNS.length; dk++) {
                var dkp = DIGIT_KEYWORD_PATTERNS[dk];
                if (dkp.digit === hdm[1] && new RegExp(dkp.regex).test(s)) { result = dkp.result; source = "digit_keyword"; break; }
            }
        }
    }

    // @spec-begin
    var COMPOUND_PATTERNS = [];
    // @spec-end
    if (result === null) {
        for (var cp = 0; cp < COMPOUND_PATTERNS.length; cp++) {
            if (new RegExp(COMPOUND_PATTERNS[cp].regex).test(s)) { result = COMPOUND_PATTERNS[cp].result; source = "compound"; break; }
        }
    }

    // @spec-begin
    var KEYWORD_PATTERNS = [{"regex":"本人|家族|患者|母|父|親|息子|娘","result":"患者本人・家族"},{"regex":"クリニック|診療所|病院|医療機関|医院|連携先","result":"連携医療機関"},{"regex":"市役所|役所|役場|保健所|行政|地域包括|包括支援|福祉課","result":"行政"}];
    // @spec-end
    if (result === null) {
        for (var kp = 0; kp < KEYWORD_PATTERNS.length; kp++) {
            if (new RegExp(KEYWORD_PATTERNS[kp].regex).test(s)) { result = KEYWORD_PATTERNS[kp].result; source = "keyword"; break; }
        }
    }

    if (result === null && /^(えー[っとー]*|えっと|えーっと|あのー?|うーん?|まあ|その|はい|うん|ん+)+$/.test(s)) {
        result = "NO_RESULT"; source = "filler_only";
    }
    if (result === null) { result = "NO_RESULT"; source = "no_match"; }
}

logger.info("[n_choice] input=\"" + input + "\" source=" + source + " => " + result);
$runner.setResult(result);

// コンテキスト保存
saveContext(result, CONTEXT_NAME, CONTEXT_DISPLAY_TYPE);

// inquiry_classifier — 用件分類（自由発話・決定論）正本 v1
// 用途: 総合相談室の「ご用件」自由発話を決定論的に分類する。OpenAI 不使用。
// 出力: 相談 / 予約 / 大代表 / 定型案内 / その他 / NO_RESULT
// ランタイム: Brekeke @General$Script（Nashorn / ES5 only）
// 由来: 髙橋 VFB-Script reference/scripts/inquiry_classifier.js のエンジン構造
//       （RULES=groups の AND ＋ exclude 排他 / no_question / filler / saveContext）を踏襲し、
//       RULES の中身を亀田 総合相談室の用件語彙＋顧客大原則に置換したもの。
// @part-id: inquiry_classifier
// @engine-version: v1
//
// 【顧客大原則（2026-06-10 浜口確定）】相談室業務に関係する電話のみ受け、予約関連は弾く。
//   優先順位: 相談 ＞ 予約 ＞ 大代表 ＞ 定型案内（RULES の配列順＝優先順位。先勝ち）。
//   ・「相談」を含む発話は必ず相談を優先（相談予約を誤って弾かない）。
//   ・相談を含まず予約系を含む発話は必ず予約として弾く。
//
// 【テンプレート】wiring（設定行・hash 除外）: 入力_用件確認 / classification / CLASSIFICATION
//   spec（規格・受入必須）: RULES / NO_QUESTION / FILLER_ONLY（@spec ブロック）

var logger = $runner.getLogger();
var INPUT_MODULE = "入力_用件確認";
var CONTEXT_NAME = "classification";
var CONTEXT_DISPLAY_TYPE = "CLASSIFICATION";

// === コンテキスト保存関数群（VFB 共通流儀）===
function _saveCheckpoint(v){try{if(!$ivr.connected())return;$ivr.exec("save2db","save",JSON.stringify({contextField:{contextName:"checkpoint",displayType:"TEXT",value:v}}));}catch(e){logger.error("[ctx]"+e);}}
function _setObj(k,v){try{$ivr.setObject(k,v);}catch(e){logger.error("[ctx]"+e);}}
function saveContext(val,name,type){var rid=$ivr.getRID();var mod=$runner.getCurrentModuleName();_saveCheckpoint(mod+"_IN");_setObj("checkpoint."+rid,mod+"_IN");if(name&&val){var r=JSON.stringify({contextField:{contextName:name,displayType:type||"TEXT",value:val}});logger.info("[saveContext2DB] "+r);try{$ivr.exec("save2db","save",r);$runner.setObject(name,val);}catch(e){logger.error("[ctx]"+e);}}_saveCheckpoint(mod+"_OUT");_setObj("checkpoint."+rid,mod+"_OUT");_setObj("saveContext."+rid,true);}
// === END ===

// @spec-begin
// ============================================================
// 用件分類ルール（配列順＝優先順位。groups は AND、exclude は排他。先勝ち）
// 亀田 OpenAI 用件プロンプト STEP2 の語彙を決定論 regex に転記。
// ============================================================
var RULES = [
    // 1. 相談（最優先 — 相談室業務。相談予約も相談として受ける）
    {
        label: "相談",
        groups: ["相談|ご相談|総合相談室|相談室|退院|退院調整|転院|ケアマネ|ケアマネージャー|在宅|介護|医療相談|ソーシャルワーカー|ソーシャルワーカ|MSW|PSW"],
        exclude: ""
    },
    // 2. 予約（相談を含まない予約・受診意図は弾く）
    {
        label: "予約",
        groups: ["予約|ご予約|受診予約|外来予約|予約変更|予約の変更|予約確認|予約の確認|受診|診察|外来|キャンセル|取り消し|取消"],
        exclude: ""
    },
    // 3. 大代表（代表番号・他部署・誤着信）
    {
        label: "大代表",
        groups: ["代表|代表番号|大代表|別の部署|他の部署|違う部署|別の窓口|かけ間違|間違え|担当部署"],
        exclude: ""
    },
    // 4. 定型案内（場所・時間・番号などの案内）
    {
        label: "定型案内",
        groups: ["場所|駐車場|行き方|道順|アクセス|受付時間|診療時間|外来時間|面会時間|何時|営業時間|電話番号|番号"],
        exclude: ""
    }
];

// 用件として意味をなさない応答（→ NO_RESULT）。
var NO_QUESTION = /^(特にありません|特にないです|特にない|ないです|ありません|なし|無し|大丈夫です|だいじょうぶです|結構です|けっこうです|以上です|いじょうです)$/;
var FILLER_ONLY = /^(えー[っとー]*|えっと|えーっと|あのー?|うーん?|まあ|その|はい|うん|ん+)+$/;
// @spec-end

var rawInput = $runner.getResult(INPUT_MODULE);
logger.info("[inquiry_classifier] rawInput: " + rawInput);

var result = null;
var source = "";

if (rawInput === null || rawInput === undefined || rawInput === "") {
    result = "NO_RESULT"; source = "empty";
} else {
    var s = String(rawInput);
    var normalized = s.replace(/[、。,.!?！？\s\r\n\t]/g, "");
    logger.info("[inquiry_classifier] normalized: " + normalized);

    if (normalized === "") { result = "NO_RESULT"; source = "empty_after_normalize"; }
    // 用件なし応答
    else if (NO_QUESTION.test(normalized)) { result = "NO_RESULT"; source = "no_question"; }
    // フィラーのみ
    else if (FILLER_ONLY.test(normalized)) { result = "NO_RESULT"; source = "filler_only"; }
    // 数字のみ（用件として解釈不能）
    else if (/^[0-9０-９]+$/.test(normalized)) { result = "NO_RESULT"; source = "digits_only"; }

    // RULES マッチング（優先順位＝配列順・先勝ち）
    if (result === null) {
        for (var i = 0; i < RULES.length; i++) {
            var rule = RULES[i];
            if (rule.exclude !== "" && new RegExp(rule.exclude).test(normalized)) { continue; }
            var allGroupsMatch = true;
            for (var g = 0; g < rule.groups.length; g++) {
                if (!new RegExp(rule.groups[g]).test(normalized)) { allGroupsMatch = false; break; }
            }
            if (allGroupsMatch) { result = rule.label; source = "rule_match[" + i + "]"; break; }
        }
    }

    // どのルールにも該当しないが何らかの発話あり → その他（伝言・折返しの安全な受け皿）
    if (result === null) { result = "その他"; source = "other_fallback"; }
}

logger.info("[inquiry_classifier] input=\"" + rawInput + "\" source=" + source + " => " + result);
$runner.setResult(result);
saveContext(result, CONTEXT_NAME, CONTEXT_DISPLAY_TYPE);

// n_choice — N択分類 + コンテキスト保存（決定論・正本 v4）
// 用途: DTMF（プッシュ番号）または音声キーワードで N 択メニューを判定する汎用エンジン。
//       OpenAI を使わず、正規化 → DTMF_MAP → token/keyword 正規表現で決定論的に分類する。
// 出力: 選択肢ラベル / NO_RESULT
// ランタイム: Brekeke @General$Script（Nashorn / ES5 only）
// 由来: 髙橋 VFB-Script reference/scripts/n_choice.js (v4) を VFB の DoD に載せた正本。
// @part-id: n_choice
// @engine-version: v4
//
// 【テンプレート（設定行 — 施設・設問ごとに充填。hash 認定では除外対象）】
//   入力_相談区分確認          直前の入力（STT/DTMF）モジュール名（wiring）
//   patientCategory          保存先 context 名（例: callerType）（wiring）
//   TEXT  context の displayType（例: TEXT）（wiring）
//   {"1":"入院","2":"外来","3":"新規"}              {"1":"ラベルA","2":"ラベルB",...} 数字→ラベル（spec）
//   []             [{regex:"...",result:"ラベル"},...] 完全一致トークン（spec）
//   [][{digit:"1",regex:"...",result:"ラベル"},...] 先頭数字＋語（spec）
//   []     [{regex:"...",result:"ラベル"},...] 複合語（先に評価）（spec）
//   [{"regex":"入院","result":"入院"},{"regex":"外来|通院","result":"外来"},{"regex":"新規|初めて|はじめて|初診","result":"新規"}]      [{regex:"...",result:"ラベル"},...] 単独キーワード（spec）
//
// 【判定順】空 → 正規化 → DTMF（単一数字）→ TOKEN → 先頭数字+語 → 複合 → 単独keyword
//          → filler のみ → no_match（いずれも NO_RESULT に倒す）

var logger = $runner.getLogger();
var INPUT_MODULE = "入力_相談区分確認";
var CONTEXT_NAME = "patientCategory";
var CONTEXT_DISPLAY_TYPE = "TEXT";

// === コンテキスト保存関数群（VFB 共通流儀: save2db + setObject + checkpoint）===
function _saveCheckpoint(value) {
    try { if (!$ivr.connected()) return; $ivr.exec("save2db", "save", JSON.stringify({ contextField: { contextName: "checkpoint", displayType: "TEXT", value: value } })); } catch (e) { logger.error("[saveContext2DB] Checkpoint: " + e); }
}
function _setObj(k, v) { try { $ivr.setObject(k, v); } catch (e) { logger.error("[saveContext2DB] setObj: " + e); } }
function saveContext(val, name, type) {
    var rid = $ivr.getRID(); var mod = $runner.getCurrentModuleName();
    _saveCheckpoint(mod + "_IN"); _setObj("checkpoint." + rid, mod + "_IN");
    if (name && val) { var req = JSON.stringify({ contextField: { contextName: name, displayType: type || "TEXT", value: val } }); logger.info("[saveContext2DB] " + req); try { $ivr.exec("save2db", "save", req); $runner.setObject(name, val); } catch (e) { logger.error("[saveContext2DB] " + e); } }
    _saveCheckpoint(mod + "_OUT"); _setObj("checkpoint." + rid, mod + "_OUT"); _setObj("saveContext." + rid, true);
}
// === END ===

var input = $runner.getResult(INPUT_MODULE);
logger.info("[n_choice] raw input: " + input);

var result = null;
var source = "";

if (input === null || input === undefined || input === "") {
    result = "NO_RESULT"; source = "empty";
} else {
    var s = String(input);
    s = s.replace(/[０-９]/g, function(c) { return String.fromCharCode(c.charCodeAt(0) - 0xFEE0); });
    s = s.replace(/[、。,.:;!?！？「」『』（）()\s\r\n\t]/g, "");
    s = s.replace(/^(えーと|えーっと|えー|あのー|あの|うーんと|うーん|まー|まあ|そうですね|えっと|そのー|あー|んー|んーと|ねえ|ちょっと)+/g, "");
    s = s.replace(/(えーと|えーっと|えー|あのー|あの|うーんと|うーん|まー|まあ|そうですね|えっと|そのー|あー|んー|んーと|ねえ|ちょっと)+$/g, "");
    // 方言/敬語/タメ口 接尾辞除去 (DIALECT/POLITE/CASUAL)
    s = s.replace(/(だべさ|だべ|っしょ|べし|だす|んだ|じゃん|だよね|じゃね|やん|やねん|やで|やんか|やわ|ねん|やろ|じゃけん|じゃけ|けん|ばい|たい|さー|さあ)$/g, "");
    s = s.replace(/(でございます|ございます|いただけますか|いただきたい|させていただきたい|でしょうか|いたします|ですよね|ですわ|だわ)$/g, "");
    s = s.replace(/(だよ|だね|だぜ|だろ|じゃね|じゃん|っす|すか|かよ|だっけ|っけ|だわ|やん|やろ|やで|けど|けんど|だに|ずら|だら)$/g, "");
    s = s.replace(/(です|でお願いします|お願いします|なんですけど|にお願い|ですけど|なんですが|をお願い)$/g, "");
    // AmiVoice カテゴリ重複正規化: "再診再診" → "再診"
    if (s.length >= 4) {
        for (var dl = Math.floor(s.length / 2); dl >= 2; dl--) {
            var chunk = s.substring(0, dl);
            var rep = new RegExp("^(" + chunk.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")+$");
            if (rep.test(s)) { s = chunk; break; }
        }
    }
    var trimmed = s.replace(/^([0-9])(です|だ|でお願いします|でお願い|ね|よ|かな)+$/, "$1");
    if (trimmed !== s) { logger.info("[n_choice] trimmed: " + s + " => " + trimmed); s = trimmed; }
    logger.info("[n_choice] normalized: " + s);
    if (s === "") { result = "NO_RESULT"; source = "empty_after_normalize"; }

    // @spec-begin
    var DTMF_MAP = {"1":"入院","2":"外来","3":"新規"};
    // @spec-end
    if (result === null && /^[0-9]$/.test(s)) {
        if (DTMF_MAP[s] !== undefined) { result = DTMF_MAP[s]; source = "dtmf"; }
        else { result = "NO_RESULT"; source = "dtmf_invalid"; }
    }

    // @spec-begin
    var TOKEN_MAP = [];
    // @spec-end
    if (result === null) {
        for (var ti = 0; ti < TOKEN_MAP.length; ti++) {
            if (new RegExp("^(" + TOKEN_MAP[ti].regex + ")$").test(s)) { result = TOKEN_MAP[ti].result; source = "token"; break; }
        }
    }

    // @spec-begin
    var DIGIT_KEYWORD_PATTERNS = [];
    // @spec-end
    if (result === null) {
        var hdm = s.match(/^([0-9])/);
